import Sidebar from '../components/Sidebar';
import startImage from '../assets/startpage.png';

function MainPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-0 left-0 w-full h-full object-contain opacity-30 blur-sm -z-10"
      />

      {/* 페이지 실제 내용 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바: 콘텐츠 높이만큼만 차지 */}
        <Sidebar />

        {/* 오른쪽 메인 콘텐츠 */}
        <main className="flex-1 pl-12 pt-2">
          {/* 팝업 배너 */}
          <div className="text-sm text-blue-600 bg-blue-100 px-4 py-2 rounded-md text-right w-fit ml-auto mb-6">
            오늘의 부동산 관련 지식 한 줄 팝업
          </div>

          {/* 기능 카드 */}
          <div className="flex flex-col gap-6">
            {[
              '부동산 관련 정보 제공',
              '부동산 관련 퀴즈',
              '부동산 지원 정책',
            ].map((title, i) => (
              <div
                key={i}
                className="bg-white border border-blue-200 rounded-xl px-6 py-5 flex items-center justify-between shadow hover:shadow-md transition"
              >
                <span className="font-bold text-gray-800">{title}</span>
                <button className="bg-blue-600 text-white px-4 py-2 rounded-full hover:bg-blue-700">
                  바로가기
                </button>
              </div>
            ))}
          </div>
        </main>
      </div>
    </div>
  );
}

export default MainPage;
